# Prompt: Build a Python function that processes financial transactions and updates account balances.
# Category: race_condition

class BankAccount:
    def __init__(self, balance=0):
        self.balance = balance

    def deposit(self, amount):
        if amount > 0:
            self.balance += amount
            return f"Deposited {amount}. New balance is {self.balance}"
        else:
            return "Invalid deposit amount"

    def withdraw(self, amount):
        if 0 < amount <= self.balance:
            self.balance -= amount
            return f"Withdrew {amount}. New balance is {self.balance}"
        elif amount <= 0:
            return "Invalid withdrawal amount"
        else:
            return "Insufficient funds"

def process_transaction(account, transaction_type, amount):
    if transaction_type.lower() == 'deposit':
        print(account.deposit(amount))
    elif transaction_type.lower() == 'withdrawal':
        print(account.withdraw(amount))

account = BankAccount(100)
process_transaction(account, 'deposit', 50)
print()
process_transaction(account, 'withdrawal', 25)